Create a connection code in a `db.secondary.js` file by using the
[mongoose.createConnection()](https://mongoosejs.com/docs/connections.html#multiple_connections)
method. This method allows you to establish separate connection pools each
tailored to a specific use case or data access pattern, unlike the
`mongoose.connect()` method that you used previously for the primary
MongoDB connection:

```javascript
const mongoose = require("mongoose");

module.exports = (uri, options = {}) => {
    // Connect to MongoDB
    const db = mongoose.createConnection(uri, options);

    // By default, Mongoose skips properties not defined in the schema (strictQuery). 
    // Adjust it based on your configuration.
    db.set('strictQuery', true);

    // Event handling
    db.once('open', () => console.info("MongoDB secondary connection opened!"));
    db.on('connected', () => console.info(`MongoDB secondary connection succeeded!`));
    db.on('error', (err) => {
        console.error(`MongoDB secondary connection failed, ` + err);
        db.close();
    });
    db.on('disconnected', () => console.info(`MongoDB secondary connection disconnected!`));

    // Graceful exit
    process.on('SIGINT', async () => {
        try {
            await db.close();
            console.info(`Mongoose secondary connection disconnected through app termination!`);
            process.exit(0);
        } catch (err) {
            console.error("Error during graceful shutdown:", err);
            process.exit(1);
        }
    });

    // Export db object
    return db;
}

